function report = runDegradedSyntheticSplit(options)
%RUNDEGRADEDSYNTHETICSPLIT Tune or evaluate frozen degraded synthetic cases.
%
% Complete renderer configurations—not pixels—are split between tuning and
% held-out suites. Tuning sees only tuning fixtures. Held-out mode requires
% frozen SGM parameters in the committed split manifest. Traceability:
% algo/main.tex Secs. 10.2-10.5 and 14.2/14.6; Eqs. (71)-(75), (121)-(133).

arguments
    options.Mode (1, 1) string ...
        {mustBeMember(options.Mode, ["tune", "heldout", ...
        "fit-confidence", "assess-confidence", ...
        "fit-hybrid", "assess-hybrid"])} = "tune"
    options.SplitFile (1, 1) string = ""
    options.UseParallel (1, 1) logical = true
    options.NumWorkers (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 0
end

root = fileparts(fileparts(mfilename("fullpath")));
oldPath = path;
addpath(fullfile(root, "src"));
cleanup = onCleanup(@() path(oldPath));
if strlength(options.SplitFile) == 0
    options.SplitFile = fullfile(root, "config", "synthetic", ...
        "degraded_split_v1.json");
end
split = jsondecode(fileread(options.SplitFile));
splitFolder = fileparts(options.SplitFile);

if ismember(options.Mode, ["tune", "fit-confidence", "fit-hybrid"])
    fixtureNames = string(split.tuningFixtures);
    expectedSuite = "tuning";
else
    fixtureNames = string(split.heldoutFixtures);
    expectedSuite = "heldout";
    if ~strcmp(string(split.tuningState), "frozen") ...
            || ~isfield(split, "frozenSgm")
        error("runDegradedSyntheticSplit:ParametersNotFrozen", ...
            ["Held-out evaluation requires tuningState='frozen' and " ...
            "committed frozenSgm parameters."]);
    end
    if options.Mode == "assess-confidence" ...
            && (~isfield(split, "confidenceState") ...
            || ~strcmp(string(split.confidenceState), "frozen") ...
            || ~isfield(split, "frozenConfidence"))
        error("runDegradedSyntheticSplit:ConfidenceNotFrozen", ...
            ["Held-out confidence assessment requires " ...
            "confidenceState='frozen' and committed " ...
            "frozenConfidence parameters."]);
    end
    if options.Mode == "assess-hybrid" ...
            && (~isfield(split, "hybridState") ...
            || ~strcmp(string(split.hybridState), "frozen") ...
            || ~isfield(split, "frozenHybrid"))
        error("runDegradedSyntheticSplit:HybridNotFrozen", ...
            ["Held-out hybrid assessment requires " ...
            "hybridState='frozen' and committed frozenHybrid parameters."]);
    end
end

needHybrid = ismember(options.Mode, ["fit-hybrid", "assess-hybrid"]);
scenes = repmat(emptyScene, numel(fixtureNames), 1);
for k = 1:numel(fixtureNames)
    fixturePath = fullfile(splitFolder, fixtureNames(k));
    scenes(k) = evaluateFixture(fixturePath, split, expectedSuite, ...
        options.UseParallel, options.NumWorkers, needHybrid);
end

switch options.Mode
    case "tune"
        report = tune(scenes, split, options.SplitFile);
    case "heldout"
        report = evaluateHeldout(scenes, split, options.SplitFile);
    case "fit-confidence"
        report = fitConfidence(scenes, split, options.SplitFile);
    case "assess-confidence"
        report = assessConfidence(scenes, split, options.SplitFile);
    case "fit-hybrid"
        report = fitHybrid(scenes, split, options.SplitFile);
    case "assess-hybrid"
        report = assessHybrid(scenes, split, options.SplitFile);
end

clear cleanup
end

function report = fitConfidence(scenes, split, splitFile)
ns = numel(scenes);
margin = cell(ns, 1);
curvature = cell(ns, 1);
epe = cell(ns, 1);
weight = cell(ns, 1);
for k = 1:ns
    d = confidenceData(scenes(k));
    v = d.Valid & isfinite(d.Margin) & d.Margin >= 0 ...
        & isfinite(d.CurvatureStepCost) & d.CurvatureStepCost > 0;
    margin{k} = d.Margin(v);
    curvature{k} = d.CurvatureStepCost(v);
    epe{k} = d.EpePixels(v);
    weight{k} = ones(nnz(v), 1) ./ nnz(v);
end
c = split.confidence;
[calibrator, fit] = HeightConfidenceCalibrator.fit(vertcat(margin{:}), ...
    vertcat(curvature{:}), vertcat(epe{:}), vertcat(weight{:}), ...
    BinCount=double(c.binCount));
[reliability, precision, summary] = evaluateConfidence( ...
    scenes, calibrator, c);
report = struct("Mode", "fit-confidence", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "RecommendedConfidence", calibrator.toStruct, ...
    "Fit", fit, "Reliability", reliability, ...
    "PrecisionCoverage", precision, "Summary", summary, ...
    "HeldoutAccessed", false);

fprintf("Degraded synthetic confidence fit: %d tuning scenes\n", ns);
disp(fit.Bins);
fprintf("Tuning confidence coverage %.6f, pixel calibration MAE %.6f\n", ...
    summary.MeanSceneConfidenceCoverage, ...
    summary.MeanScenePixelCalibrationMae);
end

function report = assessConfidence(scenes, split, splitFile)
calibrator = HeightConfidenceCalibrator.fromStruct(split.frozenConfidence);
[reliability, precision, summary] = evaluateConfidence( ...
    scenes, calibrator, split.confidence);
report = struct("Mode", "assess-confidence", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "FrozenConfidence", split.frozenConfidence, ...
    "Reliability", reliability, "PrecisionCoverage", precision, ...
    "Summary", summary, "HeldoutAccessed", true);

fprintf("Degraded synthetic held-out confidence: %d scenes\n", ...
    numel(scenes));
disp(reliability);
disp(precision);
fprintf("Held-out confidence coverage %.6f, pixel calibration MAE %.6f\n", ...
    summary.MeanSceneConfidenceCoverage, ...
    summary.MeanScenePixelCalibrationMae);
end

function [reliability, precision, summary] = evaluateConfidence( ...
        scenes, calibrator, options)
ns = numel(scenes);
nb = numel(calibrator.SigmaPixels);
fractions = double(options.precisionCoverageFractions(:));
reliabilityRows = cell(ns .* nb, 10);
precisionRows = cell(ns .* numel(fractions), 8);
calibrationPixel = nan(ns, 1);
calibrationHeight = nan(ns, 1);
confidenceCoverage = nan(ns, 1);
rr = 0;
pr = 0;
for k = 1:ns
    d = confidenceData(scenes(k));
    prediction = calibrator.predict(d.Margin, ...
        d.CurvatureStepCost, d.ObservabilityPixelsPerMetre);
    v = d.Valid & prediction.Valid;
    confidenceCoverage(k) = nnz(v) ./ max(nnz(scenes(k).TruthValid), 1);
    binErrorPixel = nan(nb, 1);
    binErrorHeight = nan(nb, 1);
    binCount = zeros(nb, 1);
    for j = 1:nb
        q = v & prediction.BinIndex == j;
        binCount(j) = nnz(q);
        predictedPixel = sqrt(mean( ...
            prediction.SigmaPixels(q) .^ 2));
        empiricalPixel = sqrt(mean(d.EpePixels(q) .^ 2));
        predictedHeight = sqrt(mean( ...
            prediction.SigmaHeightMetres(q) .^ 2));
        empiricalHeight = sqrt(mean(d.HeightErrorMetres(q) .^ 2));
        binErrorPixel(j) = abs(predictedPixel - empiricalPixel);
        binErrorHeight(j) = abs(predictedHeight - empiricalHeight);
        rr = rr + 1;
        reliabilityRows(rr, :) = {scenes(k).Identifier, j, ...
            binCount(j), confidenceCoverage(k), predictedPixel, ...
            empiricalPixel, predictedHeight, empiricalHeight, ...
            binErrorPixel(j), binErrorHeight(j)};
    end
    used = binCount > 0;
    calibrationPixel(k) = sum(binCount(used) .* binErrorPixel(used)) ...
        ./ sum(binCount(used));
    calibrationHeight(k) = sum(binCount(used) .* binErrorHeight(used)) ...
        ./ sum(binCount(used));

    index = find(v);
    [~, order] = sort(prediction.SigmaPixels(index), "ascend");
    index = index(order);
    for j = 1:numel(fractions)
        n = min(numel(index), max(1, ceil(fractions(j) .* numel(index))));
        q = index(1:n);
        pr = pr + 1;
        precisionRows(pr, :) = {scenes(k).Identifier, fractions(j), ...
            n ./ numel(index), confidenceCoverage(k), ...
            sqrt(mean(d.EpePixels(q) .^ 2)), median(d.EpePixels(q)), ...
            mean(d.EpePixels(q) > double( ...
            options.badPixelThresholdPixels)), ...
            sqrt(mean(d.HeightErrorMetres(q) .^ 2))};
    end
end
reliability = cell2table(reliabilityRows, VariableNames=["Scene", "Bin", ...
    "SampleCount", "ConfidenceCoverage", "PredictedSigmaPixels", ...
    "EmpiricalEpeRmsePixels", "PredictedSigmaHeightMetres", ...
    "EmpiricalHeightRmseMetres", "AbsolutePixelCalibrationError", ...
    "AbsoluteHeightCalibrationErrorMetres"]);
precision = cell2table(precisionRows, VariableNames=["Scene", ...
    "RequestedRetainedFraction", "ActualRetainedFraction", ...
    "ConfidenceCoverage", "EpeRmsePixels", "MedianEpePixels", ...
    "BadPixelFraction", "HeightRmseMetres"]);
summary = struct( ...
    "MeanSceneConfidenceCoverage", mean(confidenceCoverage), ...
    "MeanScenePixelCalibrationMae", mean(calibrationPixel), ...
    "MeanSceneHeightCalibrationMaeMetres", mean(calibrationHeight), ...
    "SceneConfidenceCoverage", confidenceCoverage, ...
    "ScenePixelCalibrationMae", calibrationPixel, ...
    "SceneHeightCalibrationMaeMetres", calibrationHeight, ...
    "ConfidenceDefinition", ...
    "raw ZNCC second-label margin plus one-step local curvature", ...
    "CalibrationWeighting", "each complete scene has total weight one");
end

function d = confidenceData(scene)
w = scene.Wta.CorrespondenceXY;
wx = w(:, :, 1);
wy = w(:, :, 2);
tx = scene.TruthCorrespondenceXY(:, :, 1);
ty = scene.TruthCorrespondenceXY(:, :, 2);
h = scene.Wta.HeightMetres;
valid = scene.Wta.Valid & scene.TruthValid & isfinite(h) ...
    & isfinite(wx) & isfinite(wy) & isfinite(tx) & isfinite(ty) ...
    & isfinite(scene.TruthHeightMetres);
epe = nan(size(valid));
heightError = nan(size(valid));
epe(valid) = hypot(wx(valid) - tx(valid), wy(valid) - ty(valid));
heightError(valid) = h(valid) - scene.TruthHeightMetres(valid);
d = struct("Valid", valid, "EpePixels", epe, ...
    "HeightErrorMetres", heightError, "Margin", scene.Wta.CostMargin, ...
    "CurvatureStepCost", ...
    scene.Wta.LocalCurvaturePerMetreSquared ...
    .* scene.LabelSpacingMetres .^ 2, ...
    "ObservabilityPixelsPerMetre", ...
    scene.Wta.ObservabilityPixelsPerMetre);
end

function report = fitHybrid(scenes, split, splitFile)
ns = numel(scenes);
zncc = cell(ns, 1);
spin2 = cell(ns, 1);
for k = 1:ns
    zncc{k} = scenes(k).Hybrid.Zncc;
    spin2{k} = scenes(k).Hybrid.Spin2T3;
end
scales = ZnccSpin2Hybrid.fitScales(zncc, spin2);
weights = double(split.hybrid.znccWeights(:));
nc = numel(weights);
candidateRows = cell(nc, 7);
sceneRows = cell(nc .* ns, 9);
row = 0;
for j = 1:nc
    model = ZnccSpin2Hybrid(scales.ZnccScale, scales.Spin2Scale, ...
        weights(j), 1 - weights(j), double(split.hybrid.clip));
    score = nan(ns, 1);
    epe = nan(ns, 1);
    coverage = nan(ns, 1);
    bad = nan(ns, 1);
    for k = 1:ns
        cost = model.combine(scenes(k).Hybrid.Zncc, ...
            scenes(k).Hybrid.Spin2T3, ...
            scenes(k).Hybrid.Spin2T3Confidence);
        metric = volumeMetric(scenes(k), cost, split.objective);
        score(k) = metric.Score;
        epe(k) = metric.EpeRmsePixels;
        coverage(k) = metric.Coverage;
        bad(k) = metric.BadPixelFraction;
        row = row + 1;
        sceneRows(row, :) = {j, scenes(k).Identifier, weights(j), ...
            1 - weights(j), metric.Score, metric.EpeRmsePixels, ...
            metric.Coverage, metric.BadPixelFraction, ...
            metric.HeightRmseMetres};
    end
    candidateRows(j, :) = {j, weights(j), 1 - weights(j), ...
        mean(score), mean(epe), mean(coverage), mean(bad)};
end
candidateResults = cell2table(candidateRows, VariableNames=[ ...
    "Candidate", "ZnccWeight", "Spin2Weight", "MeanSceneScore", ...
    "MeanSceneEpeRmsePixels", "MeanSceneCoverage", ...
    "MeanSceneBadPixelFraction"]);
sceneResults = cell2table(sceneRows, VariableNames=["Candidate", "Scene", ...
    "ZnccWeight", "Spin2Weight", "Score", "EpeRmsePixels", ...
    "Coverage", "BadPixelFraction", "HeightRmseMetres"]);
ordered = sortrows(candidateResults, ...
    ["MeanSceneScore", "ZnccWeight"], ["ascend", "descend"]);
best = ordered(1, :);
model = ZnccSpin2Hybrid(scales.ZnccScale, scales.Spin2Scale, ...
    best.ZnccWeight, best.Spin2Weight, double(split.hybrid.clip));
recommended = model.toStruct;
recommended.candidate = best.Candidate;
recommended.tuningObjectiveScore = best.MeanSceneScore;
report = struct("Mode", "fit-hybrid", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "ScaleFit", scales, "CandidateResults", candidateResults, ...
    "CandidateSceneResults", sceneResults, ...
    "RecommendedHybrid", recommended, "Objective", split.objective, ...
    "HeldoutAccessed", false);

fprintf("Degraded synthetic hybrid fit: %d tuning scenes, %d weights\n", ...
    ns, nc);
fprintf("  weighted MAD scales [ZNCC T3]: [%.17g %.17g]\n", ...
    scales.ZnccScale, scales.Spin2Scale);
disp(candidateResults);
fprintf("Recommended weights [ZNCC T3]: [%.3f %.3f], score %.6f\n", ...
    recommended.znccWeight, recommended.spin2Weight, ...
    recommended.tuningObjectiveScore);
end

function report = assessHybrid(scenes, split, splitFile)
model = ZnccSpin2Hybrid.fromStruct(split.frozenHybrid);
ns = numel(scenes);
rows = cell(3 .* ns, 8);
for k = 1:ns
    hybrid = model.combine(scenes(k).Hybrid.Zncc, ...
        scenes(k).Hybrid.Spin2T3, ...
        scenes(k).Hybrid.Spin2T3Confidence);
    zncc = volumeMetric(scenes(k), scenes(k).Hybrid.Zncc, ...
        split.objective);
    spin2 = volumeMetric(scenes(k), scenes(k).Hybrid.Spin2T3, ...
        split.objective);
    fused = volumeMetric(scenes(k), hybrid, split.objective);
    metric = [zncc, spin2, fused];
    method = ["raw-ZNCC", "raw-Spin2T3", "frozen-hybrid"];
    for j = 1:3
        r = 3 .* (k - 1) + j;
        rows(r, :) = {scenes(k).Identifier, method(j), ...
            metric(j).Score, metric(j).EpeRmsePixels, ...
            metric(j).MedianEpePixels, metric(j).Coverage, ...
            metric(j).BadPixelFraction, metric(j).HeightRmseMetres};
    end
end
results = cell2table(rows, VariableNames=["Scene", "Method", "Score", ...
    "EpeRmsePixels", "MedianEpePixels", "Coverage", ...
    "BadPixelFraction", "HeightRmseMetres"]);
summary = groupsummary(results, "Method", "mean", ...
    ["Score", "EpeRmsePixels", "Coverage", "BadPixelFraction"]);
report = struct("Mode", "assess-hybrid", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "FrozenHybrid", split.frozenHybrid, "Results", results, ...
    "Summary", summary, "Objective", split.objective, ...
    "HeldoutAccessed", true, "Regularization", "none");

fprintf("Degraded synthetic held-out hybrid: %d scenes\n", ns);
disp(results);
disp(summary);
end

function metric = volumeMetric(scene, cost, objective)
wta = HeightSgm.aggregate(cost, scene.HeightLabelsMetres, ...
    PenaltyPerMetre=0, MaximumPenalty=0, DirectionCount=4);
projection = scene.Dense.projectHeightMap(wta.HeightMetres, wta.Valid);
metric = sceneMetric(wta.HeightMetres, projection.CorrespondenceXY, ...
    projection.Valid, scene, objective);
end

function report = tune(scenes, split, splitFile)
[penalty, maximum, direction] = candidateGrid(split.sgmGrid);
nc = numel(penalty);
ns = numel(scenes);
candidateRows = cell(nc, 8);
sceneRows = cell(nc .* ns, 10);
row = 0;
for k = 1:nc
    score = nan(ns, 1);
    epeRmse = nan(ns, 1);
    coverage = nan(ns, 1);
    bad = nan(ns, 1);
    for i = 1:ns
        metric = regularizedMetric(scenes(i), penalty(k), maximum(k), ...
            direction(k), split.objective);
        score(i) = metric.Score;
        epeRmse(i) = metric.EpeRmsePixels;
        coverage(i) = metric.Coverage;
        bad(i) = metric.BadPixelFraction;
        row = row + 1;
        sceneRows(row, :) = {k, scenes(i).Identifier, penalty(k), ...
            maximum(k), direction(k), metric.Score, ...
            metric.EpeRmsePixels, metric.Coverage, ...
            metric.BadPixelFraction, metric.HeightRmseMetres};
    end
    candidateRows(k, :) = {k, penalty(k), maximum(k), direction(k), ...
        mean(score), mean(epeRmse), mean(coverage), mean(bad)};
end
candidateResults = cell2table(candidateRows, VariableNames=[ ...
    "Candidate", "PenaltyPerMetre", "MaximumPenalty", ...
    "DirectionCount", "MeanSceneScore", "MeanSceneEpeRmsePixels", ...
    "MeanSceneCoverage", "MeanSceneBadPixelFraction"]);
sceneResults = cell2table(sceneRows, VariableNames=["Candidate", "Scene", ...
    "PenaltyPerMetre", "MaximumPenalty", "DirectionCount", "Score", ...
    "EpeRmsePixels", "Coverage", "BadPixelFraction", ...
    "HeightRmseMetres"]);
ordered = sortrows(candidateResults, ...
    ["MeanSceneScore", "PenaltyPerMetre", "MaximumPenalty", ...
    "DirectionCount"]);
best = ordered(1, :);
recommended = struct( ...
    "PenaltyPerMetre", best.PenaltyPerMetre, ...
    "MaximumPenalty", best.MaximumPenalty, ...
    "DirectionCount", best.DirectionCount, ...
    "MeanSceneScore", best.MeanSceneScore, ...
    "Candidate", best.Candidate);
report = struct("Mode", "tune", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "CandidateResults", candidateResults, ...
    "CandidateSceneResults", sceneResults, ...
    "RecommendedSgm", recommended, ...
    "Objective", split.objective, ...
    "HeldoutAccessed", false);

fprintf("Degraded synthetic SGM tuning: %d scenes, %d candidates\n", ...
    ns, nc);
disp(candidateResults);
fprintf("Recommended: penalty/m %.6g, max %.6g, %d paths; score %.6g\n", ...
    recommended.PenaltyPerMetre, recommended.MaximumPenalty, ...
    recommended.DirectionCount, recommended.MeanSceneScore);
end

function report = evaluateHeldout(scenes, split, splitFile)
p = split.frozenSgm;
ns = numel(scenes);
rows = cell(2 .* ns, 9);
for i = 1:ns
    raw = sceneMetric(scenes(i).Wta.HeightMetres, ...
        scenes(i).Wta.CorrespondenceXY, scenes(i).Wta.Valid, ...
        scenes(i), split.objective);
    frozen = regularizedMetric(scenes(i), double(p.penaltyPerMetre), ...
        double(p.maximumPenalty), double(p.directionCount), ...
        split.objective);
    rows(2 .* i - 1, :) = {scenes(i).Identifier, "raw-WTA", ...
        raw.Score, raw.EpeRmsePixels, raw.MedianEpePixels, raw.Coverage, ...
        raw.BadPixelFraction, raw.HeightRmseMetres, 0};
    rows(2 .* i, :) = {scenes(i).Identifier, "frozen-SGM", ...
        frozen.Score, frozen.EpeRmsePixels, frozen.MedianEpePixels, ...
        frozen.Coverage, frozen.BadPixelFraction, ...
        frozen.HeightRmseMetres, frozen.RuntimeSeconds};
end
results = cell2table(rows, VariableNames=["Scene", "Method", "Score", ...
    "EpeRmsePixels", "MedianEpePixels", "Coverage", ...
    "BadPixelFraction", "HeightRmseMetres", "RuntimeSeconds"]);
raw = results.Method == "raw-WTA";
sgm = results.Method == "frozen-SGM";
summary = struct( ...
    "MeanRawScore", mean(results.Score(raw)), ...
    "MeanSgmScore", mean(results.Score(sgm)), ...
    "MeanRawEpeRmsePixels", mean(results.EpeRmsePixels(raw)), ...
    "MeanSgmEpeRmsePixels", mean(results.EpeRmsePixels(sgm)), ...
    "MeanRawBadPixelFraction", mean(results.BadPixelFraction(raw)), ...
    "MeanSgmBadPixelFraction", mean(results.BadPixelFraction(sgm)));
report = struct("Mode", "heldout", ...
    "SplitIdentifier", string(split.identifier), ...
    "SplitFile", splitFile, ...
    "FixtureIdentifiers", string({scenes.Identifier}), ...
    "FrozenSgm", p, "Results", results, "Summary", summary, ...
    "Objective", split.objective, "HeldoutAccessed", true);

fprintf("Degraded synthetic held-out evaluation: %d scenes\n", ns);
disp(results);
fprintf("Mean score raw %.6g, frozen SGM %.6g\n", ...
    summary.MeanRawScore, summary.MeanSgmScore);
end

function scene = evaluateFixture(path, split, expectedSuite, ...
        useParallel, numWorkers, needHybrid)
c = jsondecode(fileread(path));
if string(c.suite) ~= expectedSuite
    error("runDegradedSyntheticSplit:SuiteMismatch", ...
        "Fixture %s belongs to suite %s, expected %s.", ...
        string(c.identifier), string(c.suite), expectedSuite);
end
renderer = SyntheticPinholeRenderer.fromJson(path);
pair = renderer.renderPair;
r = c.movingRadiometry;
moving = SyntheticRadiometry.apply(pair.MovingImage, renderer.BitDepth, ...
    string(r.kind), Gain=double(r.gain), Offset=double(r.offset), ...
    Gamma=double(r.gamma), BlurSigmaPixels=double(r.blurSigmaPixels), ...
    NoiseSigma=double(r.noiseSigma), Seed=double(r.seed));
geometry = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
levels = 2 ^ renderer.BitDepth - 1;
curve = HeightCostCurve(geometry, ...
    double(pair.ReferenceImage) ./ levels, double(moving) ./ levels, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid);
dense = DenseHeightSweep(curve);
[truthHeight, truthCorrespondence, truthValid] = truth(renderer, pair);
[z, spacing, observability] = labels(geometry, truthHeight, truthValid, ...
    renderer.SearchRangeMetres, renderer.TargetMotionPerLabelPixels);
d = split.dense;
wta = dense.runTiled(z, Channel=string(d.channel), ...
    Channels=string(d.channel), TileSize=double(d.tileSize), ...
    LabelBlockSize=double(d.labelBlockSize), StoreCostVolumes=true, ...
    UseParallel=useParallel, NumWorkers=numWorkers, ...
    MinimumSupportFraction=double(d.minimumSupportFraction));
hybrid = struct;
if needHybrid
    [yy, xx] = ndgrid(1:renderer.ImageSize(1), ...
        1:renderer.ImageSize(2));
    sparse = curve.evaluate([xx(:), yy(:)], z, ...
        Channels="Spin2T3", ...
        MinimumSupportFraction=double(d.minimumSupportFraction));
    hybrid = struct("Zncc", wta.CostVolume, ...
        "Spin2T3", reshape(sparse.Costs.Spin2T3, ...
        [renderer.ImageSize, numel(z)]), ...
        "Spin2T3Confidence", reshape(sparse.Spin2T3Confidence, ...
        [renderer.ImageSize, numel(z)]));
end
scene = struct("Identifier", string(c.identifier), ...
    "Suite", string(c.suite), "FixturePath", path, ...
    "Radiometry", string(r.kind), "Dense", dense, "Wta", wta, ...
    "TruthHeightMetres", truthHeight, ...
    "TruthCorrespondenceXY", truthCorrespondence, ...
    "TruthValid", truthValid, "HeightLabelsMetres", z, ...
    "Hybrid", hybrid, ...
    "LabelSpacingMetres", spacing, ...
    "MedianObservabilityPixelsPerMetre", observability);
end

function metric = regularizedMetric(scene, penalty, maximum, direction, ...
        objective)
timer = tic;
sgm = HeightSgm.aggregate(scene.Wta.CostVolume, ...
    scene.HeightLabelsMetres, PenaltyPerMetre=penalty, ...
    MaximumPenalty=maximum, DirectionCount=direction);
projection = scene.Dense.projectHeightMap(sgm.HeightMetres, sgm.Valid);
metric = sceneMetric(sgm.HeightMetres, projection.CorrespondenceXY, ...
    projection.Valid, scene, objective);
metric.RuntimeSeconds = toc(timer);
end

function metric = sceneMetric(h, w, valid, scene, objective)
valid = valid & scene.TruthValid & isfinite(h) ...
    & isfinite(w(:, :, 1)) & isfinite(w(:, :, 2));
wx = w(:, :, 1);
wy = w(:, :, 2);
tx = scene.TruthCorrespondenceXY(:, :, 1);
ty = scene.TruthCorrespondenceXY(:, :, 2);
epe = hypot(wx(valid) - tx(valid), wy(valid) - ty(valid));
dh = h(valid) - scene.TruthHeightMetres(valid);
coverage = nnz(valid) ./ max(nnz(scene.TruthValid), 1);
if isempty(epe)
    epeRmse = Inf;
    medianEpe = Inf;
    bad = 1;
    heightRmse = Inf;
else
    epeRmse = sqrt(mean(epe .^ 2));
    medianEpe = median(epe);
    bad = mean(epe > double(objective.badPixelThresholdPixels));
    heightRmse = sqrt(mean(dh .^ 2));
end
score = epeRmse + double(objective.coveragePenaltyPixels) ...
    .* (1 - coverage);
metric = struct("Score", score, "EpeRmsePixels", epeRmse, ...
    "MedianEpePixels", medianEpe, "Coverage", coverage, ...
    "BadPixelFraction", bad, "HeightRmseMetres", heightRmse, ...
    "RuntimeSeconds", 0);
end

function [penalty, maximum, direction] = candidateGrid(grid)
p = double(grid.penaltyPerMetre(:));
m = double(grid.maximumPenalty(:));
d = double(grid.directionCount(:));
[pp, mm, dd] = ndgrid(p, m, d);
penalty = pp(:);
maximum = mm(:);
direction = dd(:);
if grid.includeZeroPenaltyBaseline
    penalty = [0; penalty];
    maximum = [0; maximum];
    direction = [4; direction];
end
end

function [z, w, valid] = truth(renderer, pair)
[y, x] = ndgrid(1:renderer.ImageSize(1), 1:renderer.ImageSize(2));
p = [x(:), y(:)];
if renderer.SurfaceType == "step"
    [~, z, vr] = PinholeStepOracle.intersect( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.StepHeightMetres, renderer.StepDirectionENU, ...
        renderer.StepPositionMetres);
    [w, vg, inside, visible] = PinholeStepOracle.correspondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.StepHeightMetres, ...
        renderer.StepDirectionENU, ...
        PositionMetres=renderer.StepPositionMetres);
    valid = vr & vg & inside & visible;
else
    [z, ~, ~, vr] = PinholePlaneOracle.surfaceHeight( ...
        renderer.ReferenceCamera, p, renderer.TrueHeightMetres, ...
        renderer.SurfaceSlopeENU);
    [w, vg, inside] = PinholePlaneOracle.surfaceCorrespondence( ...
        renderer.ReferenceCamera, renderer.MovingCamera, p, ...
        renderer.TrueHeightMetres, renderer.SurfaceSlopeENU);
    valid = vr & vg & inside;
end
valid = valid & pair.ReferenceValid(:);
z = reshape(z, renderer.ImageSize);
w = reshape(w, [renderer.ImageSize, 2]);
valid = reshape(valid, renderer.ImageSize);
end

function [z, spacing, medianObservability] = labels( ...
        geometry, truthHeight, valid, range, targetMotion)
[y, x] = find(valid);
p = [x, y];
h = truthHeight(valid);
[~, kappa, vk] = geometry.heightDerivative(p, h, DeltaHeight=0.5);
medianObservability = median(kappa(vk));
spacing = targetMotion ./ medianObservability;
padding = max(2 .* spacing, 5);
minimum = max(range(1), floor((min(h) - padding) ./ spacing) .* spacing);
maximum = min(range(2), ceil((max(h) + padding) ./ spacing) .* spacing);
z = minimum:spacing:maximum; %#ok<BDSCI>
end

function scene = emptyScene()
scene = struct("Identifier", "", "Suite", "", "FixturePath", "", ...
    "Radiometry", "", "Dense", [], "Wta", struct, "Hybrid", struct, ...
    "TruthHeightMetres", nan(0, 0), ...
    "TruthCorrespondenceXY", nan(0, 0, 2), ...
    "TruthValid", false(0, 0), "HeightLabelsMetres", nan(1, 0), ...
    "LabelSpacingMetres", NaN, ...
    "MedianObservabilityPixelsPerMetre", NaN);
end
